const result = $input.first().json || {};

const hasUser = !!result.usuario_id;
const hasPatient = !!result.paciente_id;

if (!hasUser && !hasPatient) {
  return [{
    json: {
      resultado: 'Não encontrei histórico anterior para este telefone. Trate como primeiro atendimento e colete os dados essenciais do paciente.',
      contexto_usuario: {
        telefone: result.telefone_consulta || null,
        usuario_existente: false,
        paciente_existente: false
      }
    }
  }];
}

const brDate = (value) => {
  if (!value) return null;
  return new Date(value).toLocaleDateString('pt-BR');
};

let resumo = '🧾 Contexto do usuário no sistema:\n';

if (hasUser) {
  resumo += `\n👤 Usuário (WhatsApp): ${result.usuario_nome || 'Sem nome'}\n`;
  resumo += `📱 Telefone: ${result.telefone_consulta || '-'}\n`;
  if (result.usuario_email) resumo += `✉️ Email: ${result.usuario_email}\n`;
  resumo += `💬 Interações: ${result.total_interacoes || 0}\n`;
  if (result.primeira_interacao) resumo += `🕐 Primeira interação: ${brDate(result.primeira_interacao)}\n`;
  if (result.ultima_interacao) resumo += `🕐 Última interação: ${brDate(result.ultima_interacao)}\n`;
}

if (hasPatient) {
  resumo += `\n🦷 Paciente: ${result.paciente_nome || 'Sem nome'} (ID: ${result.paciente_id})\n`;
  if (result.data_nascimento) resumo += `🎂 Nascimento: ${brDate(result.data_nascimento)}\n`;
  if (result.convenio) resumo += `🏥 Convênio: ${result.convenio}\n`;
  if (Array.isArray(result.alergias) && result.alergias.length) resumo += `⚠️ Alergias: ${result.alergias.join(', ')}\n`;
  if (Array.isArray(result.condicoes_medicas) && result.condicoes_medicas.length) resumo += `🩺 Condições médicas: ${result.condicoes_medicas.join(', ')}\n`;
}

resumo += `\n📅 Agendamentos totais: ${result.total_agendamentos || 0}\n`;
resumo += `📌 Agendamentos futuros: ${result.total_agendamentos_futuros || 0}\n`;
if (result.proximo_agendamento) resumo += `➡️ Próximo agendamento: ${new Date(result.proximo_agendamento).toLocaleString('pt-BR')}\n`;
if (result.ultima_consulta) resumo += `⬅️ Última consulta: ${new Date(result.ultima_consulta).toLocaleString('pt-BR')}\n`;

resumo += `\n🧩 Planos de tratamento: ${result.total_planos_tratamento || 0} (ativos: ${result.planos_ativos || 0})\n`;
resumo += `📝 Prontuários: ${result.total_prontuarios || 0}\n`;
if (result.ultimo_prontuario_em) resumo += `🗂️ Último prontuário: ${brDate(result.ultimo_prontuario_em)}\n`;
resumo += `💊 Prescrições: ${result.total_prescricoes || 0}\n`;
if (result.prescricao_mais_recente) resumo += `📄 Prescrição mais recente: ${brDate(result.prescricao_mais_recente)}\n`;

resumo += `\n💰 Financeiro - Pago: R$ ${Number(result.total_pago || 0).toFixed(2)} | Pendente: R$ ${Number(result.total_pendente || 0).toFixed(2)} | Atrasado: R$ ${Number(result.total_atrasado || 0).toFixed(2)}\n`;
if (result.proximo_vencimento) resumo += `📆 Próximo vencimento: ${brDate(result.proximo_vencimento)}\n`;

return [{
  json: {
    resultado: resumo.trim(),
    contexto_usuario: {
      telefone: result.telefone_consulta || null,
      usuario_existente: hasUser,
      paciente_existente: hasPatient,
      usuario: hasUser ? {
        id: result.usuario_id,
        nome: result.usuario_nome || null,
        email: result.usuario_email || null,
        primeira_interacao: result.primeira_interacao || null,
        ultima_interacao: result.ultima_interacao || null,
        total_interacoes: result.total_interacoes || 0,
        metadados: result.usuario_metadados || null
      } : null,
      paciente: hasPatient ? {
        id: result.paciente_id,
        nome: result.paciente_nome || null,
        data_nascimento: result.data_nascimento || null,
        convenio: result.convenio || null,
        alergias: result.alergias || [],
        condicoes_medicas: result.condicoes_medicas || [],
        observacoes: result.observacoes_paciente || null
      } : null,
      historico: {
        agendamentos_total: result.total_agendamentos || 0,
        agendamentos_futuros: result.total_agendamentos_futuros || 0,
        proximo_agendamento: result.proximo_agendamento || null,
        ultima_consulta: result.ultima_consulta || null,
        planos_tratamento_total: result.total_planos_tratamento || 0,
        planos_tratamento_ativos: result.planos_ativos || 0,
        prontuarios_total: result.total_prontuarios || 0,
        ultimo_prontuario_em: result.ultimo_prontuario_em || null,
        prescricoes_total: result.total_prescricoes || 0,
        prescricao_mais_recente: result.prescricao_mais_recente || null
      },
      financeiro: {
        registros_total: result.total_registros_financeiros || 0,
        total_pago: Number(result.total_pago || 0),
        total_pendente: Number(result.total_pendente || 0),
        total_atrasado: Number(result.total_atrasado || 0),
        proximo_vencimento: result.proximo_vencimento || null
      }
    }
  }
}];
